const now = new Date(); // 获取当前时间

// 获取当前时间的 UTC 时间戳
const utcTimestamp = now.getTime() + (now.getTimezoneOffset() * 60000); // 转换为 UTC 时间戳

// 将 UTC 时间戳转换为 GMT+8
const gmtPlus8Date = new Date(utcTimestamp + (8 * 60 * 60 * 1000)); // 加上 8 小时的毫秒数

// 格式化后的日期
const finalDate = gmtPlus8Date.toISOString().replace('Z', '+08:00'); // 替换 'Z' 为 '+08:00'

return [{ json: { 
    "mobile_num": $('Standardlize input').first().json.from || $('Standardlize input').first().json.mobile_num,
    "name": "AI Chatbot",
    "message": $('Standardlize input').first().json.text,
    "timestamp": finalDate,
    "from":$('Standardlize input').first().json.from,
    "to": $('Standardlize input').first().json.to,
    "conversationId":$('Standardlize input').first().json.conversationId,
    "type":"session_message",
    "source":$('Standardlize input').first().json.source
}}];

let userName, userNum, conversationId, source, kfId, from;
const conversation = $input.first().json.conversation.map(msg => {
  conversationId = msg.conversationId;
  source = msg.source;
  if (msg.type === "user_message") {
    userName = msg.name;
    userNum = msg.mobile_num;
    kfId = msg.to;
    from = msg.from;
    return { user: msg.message };
  } else if (msg.type === "session_message") {
    return { assistant: msg.message };
  }
  else if (msg.type === "template_message") {
    return { assistant: msg.message };
  }
});

const user_history_len = 3;
const filteredConversation = (() => {
    let count = 0;
    const result = [];
    for (let i = conversation.length - 1; i >= 0; i--) {
        const item = conversation[i];
        if (item.user !== undefined) {
            count++;
            if (count > user_history_len) break;
        }
        result.unshift(item);
    }
    return result;
})();

return {
  conversation: JSON.stringify(filteredConversation, null, 2),
  messageType: $('Webhook').item.json.body.type,
  conversationId,
  userName,
  userNum,
  source,
  kfId,
  from
}

